changeSet.sql:
insert into underlying_agreement_document (id, underlying_agreement_id, file_document_uuid, consolidation_number, activation_date, scheme_version)
select nextval('underlying_agreement_document_seq'), ua.id, ua.file_document_uuid, ua.consolidation_number, ua.activation_date, 'CCA_2'
from underlying_agreement ua;

rollback.sql:
UPDATE underlying_agreement_document
SET terminated_date = null
WHERE terminated_date is not null;
